function normalizeDag(dag) {
  if (Array.isArray(dag)) {
    const v3Nodes = (dag[2] || []).map((n, i) => {
      const props = n[2] || [];
      const states = n[3] || [];
      const edges = n[4] || [];
      return [i, n[0], n[1] === "p" ? "prediction" : "entity", "", props, states, edges];
    });
    return { v: dag[0], p: dag[1], n: v3Nodes, tk: dag[3] };
  }
  return dag;
}
function resolvePath2(p) {
  if (p.startsWith("~"))
    p = join3(homedir2(), p.slice(1));
  const resolved = p.startsWith("/") ? p : join3(process.cwd(), p);
  if (!p.startsWith("/") && !p.startsWith("~")) {
    const rel = resolve2(process.cwd(), p);
    const cwd = process.cwd();
    const isDescendant = rel.startsWith(cwd + "/");
    const isSelf = rel === cwd;
    const isAncestor = cwd.startsWith(rel + "/");
    if (!isDescendant && !isSelf && !isAncestor) {
      throw new Error(`Path traversal blocked: ${p}`);
    }
    return rel;
  }
  return resolved;
}
function parseSections2(markdown) {
  const lines = markdown.split(`
`), sections = [];
  let heading = "(root)", level = 1, content = [], lineStart = 1;
  for (let i = 0;i < lines.length; i++) {
    const m2 = lines[i].match(/^##\s+(.+)/), m3 = lines[i].match(/^###\s+(.+)/);
    if (m2 && !m3) {
      if (content.length > 0 || sections.length === 0)
        sections.push({ heading, level, content: content.join(`
`).trim(), lineStart, lineEnd: i });
      heading = m2[1];
      level = 2;
      content = [];
      lineStart = i + 1;
    } else if (m3) {
      if (content.length > 0 || sections.length === 0)
        sections.push({ heading, level, content: content.join(`
`).trim(), lineStart, lineEnd: i });
      heading = m3[1];
      level = 3;
      content = [];
      lineStart = i + 1;
    } else {
      content.push(lines[i]);
    }
  }
  if (content.length > 0 || sections.length === 0)
    sections.push({ heading, level, content: content.join(`
`).trim(), lineStart, lineEnd: lines.length });
  return sections;
}
